PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?labor ?laborLabel 
WHERE {
  ?labor wdt:P361 wd:Q1233460;
         rdfs:label ?laborLabel.
  FILTER(LANG(?laborLabel) = "en")
  FILTER NOT EXISTS {
    ?labor wdt:P807 ?target.
    ?target wdt:P31/wdt:P279* wd:Q726.
  }
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?target ?targetLabel 
WHERE {
  ?target wdt:P361 wd:Q1233460.
  ?target rdfs:label ?targetLabel.
  FILTER(LANG(?targetLabel) = "en")
  {
    # Target is not a taxon (Q726)
    FILTER NOT EXISTS {
      ?target wdt:P31/wdt:P279* wd:Q726.
    }
  }
  UNION
  {
    # Target is a taxon but not killed by Heracles
    ?target wdt:P31/wdt:P279* wd:Q726.
    FILTER NOT EXISTS {
      ?target wdt:P1537 wd:Q122248.
    }
  }
}
ORDER BY ?targetLabel

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?labor ?laborLabel
WHERE {
  ?labor wdt:P361 wd:Q1233460 .
  ?labor rdfs:label ?laborLabel .
  FILTER(LANG(?laborLabel) = "en")
  OPTIONAL { ?labor wdt:P366 ?target . }
  FILTER NOT EXISTS {
    ?target wdt:P31/wdt:P279* wd:Q891729 .
    ?target wdt:P1537 wd:Q122248 .
  }
}
ORDER BY ?laborLabel
